import "server-only";

import { list, put } from "@vercel/blob";

export async function uploadBlob(name: string, body: Blob | Buffer) {
  return put(name, body, { access: "public" });
}

export async function listBlobs(prefix?: string) {
  return list({ prefix });
}

import { NextResponse } from "next/server";

import { uploadBlob } from "@/lib/vercel/blob";

export async function POST(request: Request) {
  const formData = await request.formData();
  const file = formData.get("file");
  if (!(file instanceof Blob)) return NextResponse.json({ error: "file is required" }, { status: 400 });

  const blob = await uploadBlob("uploads/" + crypto.randomUUID(), file);
  return NextResponse.json(blob);
}

const deployChecks = [
  "Create the vendor project and add production env vars",
  "Run the included smoke route after deploy",
  "Document alerting, retries, and rollback behavior",
];

export default function VercelBlobPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Vercel Blob</h1>
        <p className="text-muted-foreground">File and asset storage with deploy-ready upload route examples.</p>
      </div>
      <div className="grid gap-3">
        {deployChecks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
